async fn post_cortex_heap_block_pin(
    headers: HeaderMap,
    Path(artifact_id): Path<String>,
) -> axum::response::Response {
    let identity = match enforce_role_authorization(
        &headers,
        "post_cortex_heap_block_pin",
        None,
        "capability:heap_block_pin",
        "mutate",
        "operator",
        authz_mutation_claims("heap"),
        true,
        vec![],
        "HEAP_BLOCK_PIN_FORBIDDEN",
        "Operator role or higher is required to pin heap blocks.",
    )
    .await
    {
        Ok(identity) => identity,
        Err(response) => return response,
    };
    let actor_role = identity.role.clone();
    let actor_id = identity
        .principal
        .clone()
        .unwrap_or_else(|| actor_id_from_headers(&headers));

    let mut projections = read_heap_projection_store();
    let Some(entry) = projections
        .iter_mut()
        .find(|entry| entry.projection.artifact_id == artifact_id)
    else {
        return cortex_ux_error(
            StatusCode::NOT_FOUND,
            "HEAP_BLOCK_NOT_FOUND",
            "Heap block does not exist.",
            Some(json!({ "artifactId": artifact_id })),
        );
    };
    let updated_at = now_iso();
    entry.pinned_at = Some(updated_at.clone());
    entry.projection.updated_at = updated_at.clone();
    if let Err(err) = write_heap_projection_store(&projections) {
        return cortex_ux_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "HEAP_PROJECTION_WRITE_FAILED",
            "Failed to persist heap pin action.",
            Some(json!({ "artifactId": artifact_id, "reason": err })),
        );
    }

    let mut artifacts = read_artifacts_store();
    if let Some(artifact) = artifacts
        .iter_mut()
        .find(|item| item.artifact_id == artifact_id)
    {
        artifact.updated_at = updated_at.clone();
        let _ = write_artifacts_store(&artifacts);
    }
    let _ = append_artifact_audit(
        &artifact_id,
        "heap_pin",
        &actor_role,
        &actor_id,
        "/heap",
        None,
    );

    Json(HeapBlockActionResponse {
        accepted: true,
        artifact_id,
        action: "pin".to_string(),
        updated_at,
    })
    .into_response()
}

async fn post_cortex_heap_block_delete(
    headers: HeaderMap,
    Path(artifact_id): Path<String>,
) -> axum::response::Response {
    let identity = match enforce_role_authorization(
        &headers,
        "post_cortex_heap_block_delete",
        None,
        "capability:heap_block_delete",
        "mutate",
        "operator",
        authz_mutation_claims("heap"),
        true,
        vec![],
        "HEAP_BLOCK_DELETE_FORBIDDEN",
        "Operator role or higher is required to delete heap blocks.",
    )
    .await
    {
        Ok(identity) => identity,
        Err(response) => return response,
    };
    let actor_role = identity.role.clone();
    let actor_id = identity
        .principal
        .clone()
        .unwrap_or_else(|| actor_id_from_headers(&headers));
    let deleted_at = now_iso();

    let mut projections = read_heap_projection_store();
    let Some(entry) = projections
        .iter_mut()
        .find(|entry| entry.projection.artifact_id == artifact_id)
    else {
        return cortex_ux_error(
            StatusCode::NOT_FOUND,
            "HEAP_BLOCK_NOT_FOUND",
            "Heap block does not exist.",
            Some(json!({ "artifactId": artifact_id })),
        );
    };
    entry.deleted_at = Some(deleted_at.clone());
    entry.projection.updated_at = deleted_at.clone();
    if let Err(err) = write_heap_projection_store(&projections) {
        return cortex_ux_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "HEAP_PROJECTION_WRITE_FAILED",
            "Failed to persist heap delete action.",
            Some(json!({ "artifactId": artifact_id, "reason": err })),
        );
    }

    let mut artifacts = read_artifacts_store();
    if let Some(artifact) = artifacts
        .iter_mut()
        .find(|item| item.artifact_id == artifact_id)
    {
        artifact.status = "deleted".to_string();
        artifact.updated_at = deleted_at.clone();
        let _ = write_artifacts_store(&artifacts);
    }
    let _ = append_artifact_audit(
        &artifact_id,
        "heap_delete",
        &actor_role,
        &actor_id,
        "/heap",
        None,
    );

    Json(HeapBlockActionResponse {
        accepted: true,
        artifact_id,
        action: "delete".to_string(),
        updated_at: deleted_at,
    })
    .into_response()
}

#[derive(Deserialize)]
struct HeapBlocksContextRequest {
    block_ids: Vec<String>,
}

#[derive(Serialize)]
struct HeapBlocksContextResponse {
    context_bundle: HeapBlocksContextBundle,
}

#[derive(Serialize)]
struct HeapBlocksContextBundle {
    blocks: Vec<serde_json::Value>,
    block_count: usize,
    prepared_at: String,
}

async fn post_cortex_heap_blocks_context(
    headers: HeaderMap,
    Json(request): Json<HeapBlocksContextRequest>,
) -> axum::response::Response {
    let _actor_id = actor_id_from_headers(&headers);

    if request.block_ids.is_empty() {
        return cortex_ux_error(
            StatusCode::BAD_REQUEST,
            "HEAP_CONTEXT_EMPTY",
            "No block IDs provided for context bundling.",
            None,
        );
    }

    let projections = read_heap_projection_store();
    let requested_set: std::collections::HashSet<&str> =
        request.block_ids.iter().map(|id| id.as_str()).collect();

    let matched_blocks: Vec<serde_json::Value> = projections
        .iter()
        .filter(|entry| {
            requested_set.contains(entry.projection.artifact_id.as_str())
                && entry.deleted_at.is_none()
        })
        .map(|entry| {
            json!({
                "artifact_id": entry.projection.artifact_id,
                "title": entry.projection.title,
                "block_type": entry.projection.block_type,
                "tags": entry.projection.tags,
                "mentions": entry.projection.mentions_inline,
                "surface_json": entry.surface_json,
                "updated_at": entry.projection.updated_at,
            })
        })
        .collect();

    let block_count = matched_blocks.len();
    Json(HeapBlocksContextResponse {
        context_bundle: HeapBlocksContextBundle {
            blocks: matched_blocks,
            block_count,
            prepared_at: now_iso(),
        },
    })
    .into_response()
}

#[derive(Deserialize)]
struct ExportQuery {
    format: Option<String>,
}

async fn get_cortex_heap_block_export(
    Path(artifact_id): Path<String>,
    Query(query): Query<ExportQuery>,
) -> axum::response::Response {
    let projections = read_heap_projection_store();
    let Some(entry) = projections
        .iter()
        .find(|entry| entry.projection.artifact_id == artifact_id && entry.deleted_at.is_none())
    else {
        return cortex_ux_error(
            StatusCode::NOT_FOUND,
            "HEAP_BLOCK_NOT_FOUND",
            "Heap block does not exist.",
            Some(json!({ "artifactId": artifact_id })),
        );
    };

    let format = query.format.as_deref().unwrap_or("markdown");
    match format {
        "json" => {
            let payload = json!({
                "artifact_id": entry.projection.artifact_id,
                "title": entry.projection.title,
                "block_type": entry.projection.block_type,
                "tags": entry.projection.tags,
                "mentions": entry.projection.mentions_inline,
                "surface_json": entry.surface_json,
                "updated_at": entry.projection.updated_at,
            });
            Json(payload).into_response()
        }
        _ => {
            // Markdown export with YAML frontmatter
            let mut md = String::new();
            md.push_str("---\n");
            md.push_str(&format!("title: \"{}\"\n", entry.projection.title));
            md.push_str(&format!(
                "artifact_id: \"{}\"\n",
                entry.projection.artifact_id
            ));
            md.push_str(&format!(
                "block_type: \"{}\"\n",
                entry.projection.block_type
            ));
            if !entry.projection.tags.is_empty() {
                md.push_str("tags:\n");
                for tag in &entry.projection.tags {
                    md.push_str(&format!("  - \"{}\"\n", tag));
                }
            }
            if !entry.projection.mentions_inline.is_empty() {
                md.push_str("mentions:\n");
                for mention in &entry.projection.mentions_inline {
                    md.push_str(&format!("  - \"[[{}]]\"\n", mention));
                }
            }
            md.push_str(&format!(
                "updated_at: \"{}\"\n",
                entry.projection.updated_at
            ));
            md.push_str("---\n\n");
            md.push_str(&format!("# {}\n\n", entry.projection.title));
            md.push_str(&format!(
                "```json\n{}\n```\n",
                serde_json::to_string_pretty(&entry.surface_json).unwrap_or_default()
            ));

            axum::response::Response::builder()
                .status(StatusCode::OK)
                .header("content-type", "text/markdown; charset=utf-8")
                .header(
                    "content-disposition",
                    format!(
                        "attachment; filename=\"{}.md\"",
                        entry.projection.artifact_id
                    ),
                )
                .body(axum::body::Body::from(md))
                .unwrap_or_else(|_| StatusCode::INTERNAL_SERVER_ERROR.into_response())
        }
    }
}

#[derive(Serialize)]
struct HeapBlockHistoryResponse {
    artifact_id: String,
    versions: Vec<HeapBlockVersion>,
    #[serde(default)]
    revisions: Vec<HeapArtifactRevisionSummary>,
    #[serde(default)]
    lineage: Vec<HeapLineageRelation>,
    #[serde(default)]
    legacy_duplicates: Vec<SpaceLegacyPromptGroup>,
}

#[derive(Serialize)]
struct HeapBlockVersion {
    version: usize,
    timestamp: String,
    mutation_type: String,
    actor: String,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct HeapArtifactRevisionSummary {
    revision_id: String,
    revision_number: u64,
    created_at: String,
    created_by: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    parent_revision_id: Option<String>,
    published: bool,
    #[serde(skip_serializing_if = "Option::is_none")]
    content_hash: Option<String>,
}

#[derive(Serialize)]
#[serde(rename_all = "camelCase")]
struct HeapLineageRelation {
    relation: String,
    artifact_id: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    title: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    block_type: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    subtitle: Option<String>,
}

fn semantic_relation_targets(surface_json: &Value) -> Vec<(String, String)> {
    let mut relations = Vec::new();
    let push_string =
        |relations: &mut Vec<(String, String)>, relation: &str, value: Option<String>| {
            if let Some(value) = value.filter(|candidate| !candidate.trim().is_empty()) {
                relations.push((relation.to_string(), value));
            }
        };
    push_string(
        &mut relations,
        "parent_artifact",
        surface_string_field(surface_json, "parent_artifact_id"),
    );
    push_string(
        &mut relations,
        "artifact",
        surface_string_field(surface_json, "artifact_id"),
    );
    push_string(
        &mut relations,
        "prompt_template",
        surface_string_field(surface_json, "prompt_template_artifact_id"),
    );
    push_string(
        &mut relations,
        "prompt_execution",
        surface_string_field(surface_json, "prompt_execution_artifact_id"),
    );
    push_string(
        &mut relations,
        "parent_run",
        surface_string_field(surface_json, "parent_run_id"),
    );
    push_string(
        &mut relations,
        "run",
        surface_string_field(surface_json, "run_id"),
    );
    if let Some(data) = surface_structured_data(surface_json) {
        if let Some(children) = data.get("child_run_ids").and_then(|value| value.as_array()) {
            for child in children {
                if let Some(child_id) = child
                    .as_str()
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                {
                    relations.push(("child_run".to_string(), child_id.to_string()));
                }
            }
        }
    }
    relations
}

fn build_heap_lineage_relations(
    artifact_id: &str,
    projections: &[HeapProjectionRecord],
) -> Vec<HeapLineageRelation> {
    let title_map = projections
        .iter()
        .map(|entry| {
            (
                entry.projection.artifact_id.clone(),
                (
                    entry.projection.title.clone(),
                    entry.projection.block_type.clone(),
                    surface_string_field(&entry.surface_json, "type"),
                ),
            )
        })
        .collect::<BTreeMap<_, _>>();

    let current = projections
        .iter()
        .find(|entry| entry.projection.artifact_id == artifact_id);
    let mut relations = current
        .map(|entry| {
            semantic_relation_targets(&entry.surface_json)
                .into_iter()
                .map(|(relation, target_id)| {
                    let target = title_map.get(&target_id);
                    HeapLineageRelation {
                        relation,
                        artifact_id: target_id,
                        title: target.map(|value| value.0.clone()),
                        block_type: target.map(|value| value.1.clone()),
                        subtitle: target.and_then(|value| value.2.clone()),
                    }
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();

    for candidate in projections {
        if candidate.projection.artifact_id == artifact_id {
            continue;
        }
        for (relation, target_id) in semantic_relation_targets(&candidate.surface_json) {
            if target_id != artifact_id {
                continue;
            }
            relations.push(HeapLineageRelation {
                relation: format!("inbound_{relation}"),
                artifact_id: candidate.projection.artifact_id.clone(),
                title: Some(candidate.projection.title.clone()),
                block_type: Some(candidate.projection.block_type.clone()),
                subtitle: surface_string_field(&candidate.surface_json, "type"),
            });
        }
    }

    relations.sort_by(|left, right| {
        left.relation
            .cmp(&right.relation)
            .then_with(|| left.artifact_id.cmp(&right.artifact_id))
    });
    relations.dedup_by(|left, right| {
        left.relation == right.relation && left.artifact_id == right.artifact_id
    });
    relations
}

fn build_legacy_duplicate_groups(artifact_id: &str) -> Vec<SpaceLegacyPromptGroup> {
    let artifacts = read_artifacts_store();
    let Some(current) = artifacts
        .iter()
        .find(|entry| entry.artifact_id == artifact_id)
    else {
        return Vec::new();
    };
    let matching = artifacts
        .iter()
        .filter(|entry| entry.artifact_id != artifact_id)
        .filter(|entry| entry.title == current.title && entry.content_hash == current.content_hash)
        .map(|entry| entry.artifact_id.clone())
        .collect::<Vec<_>>();
    if matching.is_empty() {
        return Vec::new();
    }
    let mut artifact_ids = vec![artifact_id.to_string()];
    artifact_ids.extend(matching);
    vec![SpaceLegacyPromptGroup {
        title: current.title.clone(),
        content_hash: Some(current.content_hash.clone()),
        artifact_ids,
    }]
}

async fn get_cortex_heap_block_history(
    Path(artifact_id): Path<String>,
) -> axum::response::Response {
    let projections = read_heap_projection_store();
    let exists = projections
        .iter()
        .any(|entry| entry.projection.artifact_id == artifact_id);
    if !exists {
        return cortex_ux_error(
            StatusCode::NOT_FOUND,
            "HEAP_BLOCK_NOT_FOUND",
            "Heap block does not exist.",
            Some(json!({ "artifactId": artifact_id })),
        );
    }

    // Read audit log and filter for this artifact
    let all_audit: Vec<serde_json::Value> = {
        let path = cortex_ux_artifact_audit_log_path();
        let raw = match std::fs::read_to_string(&path) {
            Ok(content) => content,
            Err(_) => String::new(),
        };
        raw.lines()
            .filter_map(|line| serde_json::from_str::<serde_json::Value>(line).ok())
            .filter(|entry| {
                entry.get("artifact_id").and_then(|v| v.as_str()) == Some(artifact_id.as_str())
            })
            .collect()
    };

    let versions: Vec<HeapBlockVersion> = all_audit
        .iter()
        .enumerate()
        .map(|(idx, entry)| HeapBlockVersion {
            version: idx + 1,
            timestamp: entry
                .get("timestamp")
                .and_then(|v| v.as_str())
                .unwrap_or("unknown")
                .to_string(),
            mutation_type: entry
                .get("action")
                .and_then(|v| v.as_str())
                .unwrap_or("unknown")
                .to_string(),
            actor: entry
                .get("actor_id")
                .and_then(|v| v.as_str())
                .unwrap_or("unknown")
                .to_string(),
        })
        .collect();
    let mut revisions = read_artifact_revisions()
        .into_iter()
        .filter(|revision| revision.artifact_id == artifact_id)
        .map(|revision| HeapArtifactRevisionSummary {
            revision_id: revision.revision_id,
            revision_number: revision.revision_number,
            created_at: revision.created_at,
            created_by: revision.created_by,
            parent_revision_id: revision.parent_revision_id,
            published: revision.published,
            content_hash: Some(revision.content_hash),
        })
        .collect::<Vec<_>>();
    revisions.sort_by(|left, right| right.revision_number.cmp(&left.revision_number));
    let lineage = build_heap_lineage_relations(&artifact_id, &projections);
    let legacy_duplicates = build_legacy_duplicate_groups(&artifact_id);

    Json(HeapBlockHistoryResponse {
        artifact_id,
        versions,
        revisions,
        lineage,
        legacy_duplicates,
    })
    .into_response()
}

async fn post_cortex_heap_block_a2ui_feedback(
    headers: HeaderMap,
    Path(artifact_id): Path<String>,
    Json(request): Json<CortexA2uiFeedbackRequest>,
) -> axum::response::Response {
    let identity = match enforce_role_authorization(
        &headers,
        "post_cortex_heap_block_a2ui_feedback",
        None,
        "capability:heap_emit",
        "mutate",
        "operator",
        authz_mutation_claims("heap"),
        true,
        vec![],
        "HEAP_A2UI_FEEDBACK_FORBIDDEN",
        "Operator role or higher is required to submit A2UI feedback.",
    )
    .await
    {
        Ok(identity) => identity,
        Err(response) => return response,
    };

    let decision = request.decision.trim();
    if decision.is_empty() {
        return cortex_ux_error(
            StatusCode::BAD_REQUEST,
            "A2UI_FEEDBACK_INVALID",
            "decision is required.",
            Some(json!({ "artifactId": artifact_id })),
        );
    }

    let parent_projection = {
        let projections = read_heap_projection_store();
        projections
            .iter()
            .find(|entry| entry.projection.artifact_id == artifact_id && entry.deleted_at.is_none())
            .cloned()
    };

    let Some(parent_projection) = parent_projection else {
        return cortex_ux_error(
            StatusCode::NOT_FOUND,
            "HEAP_BLOCK_NOT_FOUND",
            "Heap block does not exist.",
            Some(json!({ "artifactId": artifact_id })),
        );
    };

    let actor_role = identity.role.clone();
    let actor_id = identity
        .principal
        .clone()
        .unwrap_or_else(|| actor_id_from_headers(&headers));
    let submitted_by = actor_id_from_headers(&headers);
    let stored_at = now_iso();
    let feedback_artifact_id =
        format!("feedback_{}_{}", artifact_id, Utc::now().timestamp_millis());
    let feedback_notes = request
        .feedback
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let feedback_summary = feedback_notes
        .clone()
        .unwrap_or_else(|| format!("Steward marked {decision}."));

    let payload = json!({
        "schema_version": "1.0.0",
        "mode": "heap",
        "workspace_id": parent_projection.projection.workspace_id.clone(),
        "source": {
            "agent_id": actor_id.clone(),
            "request_id": format!("a2ui_feedback_{}_{}", artifact_id, Utc::now().timestamp_millis()),
            "emitted_at": stored_at.clone(),
            "session_id": format!("heap_feedback:{}", parent_projection.projection.workspace_id),
        },
        "block": {
            "type": "steward_feedback",
            "title": format!("Steward feedback for {}", parent_projection.projection.title),
        },
        "content": {
            "payload_type": "structured_data",
            "structured_data": {
                "type": "steward_feedback",
                "artifact_id": artifact_id.clone(),
                "parent_artifact_id": parent_projection.projection.artifact_id.clone(),
                "space_id": parent_projection.projection.workspace_id.clone(),
                "decision": decision,
                "feedback": feedback_summary.clone(),
                "message": feedback_summary,
                "notes": feedback_notes,
                "submitted_by": submitted_by,
                "submitted_at": stored_at.clone(),
            }
        },
        "projection_hints": {
            "mirror_mentions_to_relations": true,
            "relation_map_version": "relations_v1",
            "files_key_format": "hash:file_size",
        },
        "crdt_projection": {
            "artifact_id": feedback_artifact_id,
        }
    });

    let emit_request = match parse_emit_heap_block(payload) {
        Ok(request) => request,
        Err(err) => {
            return cortex_ux_error(
                heap_emit_error_status(&err.code),
                &err.code,
                &err.message,
                err.details,
            );
        }
    };

    match emit_heap_block_core(emit_request, actor_id, actor_role) {
        Ok(_) => Json(CortexA2uiFeedbackResponse {
            accepted: true,
            artifact_id,
            feedback_artifact_id,
            stored_at,
        })
        .into_response(),
        Err(response) => response,
    }
}

