async fn get_siq_health() -> impl IntoResponse {
    let log_dir = siq_log_dir();
    let coverage_path = siq_coverage_path();
    let dependency_path = siq_dependency_closure_path();
    let gate_path = siq_gate_summary_path(None);
    let projection_path = siq_graph_projection_path(None);
    let runs_dir = siq_runs_dir();

    let coverage_last_modified = file_last_modified_secs(&coverage_path);
    let dependency_last_modified = file_last_modified_secs(&dependency_path);
    let gate_last_modified = file_last_modified_secs(&gate_path);
    let projection_last_modified = file_last_modified_secs(&projection_path);

    let mut latest_run_last_modified: Option<u64> = None;
    let mut runs_count = 0usize;
    if let Ok(entries) = fs::read_dir(&runs_dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            if path.extension().and_then(|ext| ext.to_str()) != Some("json") {
                continue;
            }
            runs_count += 1;
            if let Some(modified) = file_last_modified_secs(&path) {
                latest_run_last_modified =
                    Some(latest_run_last_modified.unwrap_or(0).max(modified));
            }
        }
    }

    let coverage_exists = coverage_path.exists();
    let dependency_exists = dependency_path.exists();
    let gate_exists = gate_path.exists();
    let projection_exists = projection_path.exists();
    let coverage_fresh = coverage_last_modified
        .map(|ts| now_secs().saturating_sub(ts) <= SIQ_STALE_AFTER_SECS)
        .unwrap_or(false);
    let dependency_fresh = dependency_last_modified
        .map(|ts| now_secs().saturating_sub(ts) <= SIQ_STALE_AFTER_SECS)
        .unwrap_or(false);
    let gate_fresh = gate_last_modified
        .map(|ts| now_secs().saturating_sub(ts) <= SIQ_STALE_AFTER_SECS)
        .unwrap_or(false);
    let projection_fresh = projection_last_modified
        .map(|ts| now_secs().saturating_sub(ts) <= SIQ_STALE_AFTER_SECS)
        .unwrap_or(false);

    let all_exist = coverage_exists && dependency_exists && gate_exists && projection_exists;
    let all_fresh = coverage_fresh && dependency_fresh && gate_fresh && projection_fresh;
    let any_exists = coverage_exists || dependency_exists || gate_exists || projection_exists;
    let status = if all_exist && all_fresh {
        "ok".to_string()
    } else if any_exists {
        "degraded".to_string()
    } else {
        "missing".to_string()
    };

    Json(SiqHealth {
        status,
        siq_log_dir: log_dir.display().to_string(),
        schema_version: SIQ_SCHEMA_VERSION.to_string(),
        coverage_exists,
        dependency_exists,
        gate_exists,
        projection_exists,
        runs_count,
        latest_run_last_modified,
        coverage_fresh,
        dependency_fresh,
        gate_fresh,
        projection_fresh,
    })
    .into_response()
}

async fn get_system_logs_streams(headers: HeaderMap) -> axum::response::Response {
    if let Err(response) = enforce_role_authorization(
        &headers,
        "get_system_logs_streams",
        None,
        "capability:system_logs_streams",
        "read",
        "operator",
        vec![],
        true,
        vec![],
        "SYSTEM_LOGS_STREAMS_FORBIDDEN",
        "Operator role or higher is required to list curated log streams.",
    )
    .await
    {
        return response;
    }

    Json(crate::services::system_logs::inventory_response(&now_iso())).into_response()
}

async fn get_system_logs_stream_tail(
    headers: HeaderMap,
    Path(stream_id): Path<String>,
    Query(query): Query<SystemLogsTailQuery>,
) -> axum::response::Response {
    let stream_id = stream_id.trim().to_string();
    let Some((def, _path)) = crate::services::system_logs::resolve_stream(&stream_id) else {
        return cortex_ux_error(
            StatusCode::NOT_FOUND,
            "SYSTEM_LOG_STREAM_NOT_FOUND",
            "Unknown log stream.",
            Some(crate::services::system_logs::stream_missing_error(
                &stream_id,
            )),
        );
    };

    if let Err(response) = enforce_role_authorization(
        &headers,
        "get_system_logs_stream_tail",
        None,
        "capability:system_logs_tail",
        "read",
        def.required_role,
        vec![],
        true,
        vec![],
        "SYSTEM_LOG_STREAM_FORBIDDEN",
        "Insufficient role for this log stream.",
    )
    .await
    {
        return response;
    }

    let cursor = query.cursor.unwrap_or(0);
    let limit = query.limit.unwrap_or(200);
    match crate::services::system_logs::tail_stream(&stream_id, cursor, limit) {
        Ok((_def, response)) => {
            Json(serde_json::to_value(response).unwrap_or_default()).into_response()
        }
        Err(reason) => cortex_ux_error(
            StatusCode::SERVICE_UNAVAILABLE,
            "SYSTEM_LOG_TAIL_FAILED",
            "Failed to tail log stream.",
            Some(json!({ "streamId": stream_id, "reason": reason })),
        ),
    }
}

