    #[test]
    fn preserve_user_provider_metadata_strips_managed_runtime_keys() {
        let metadata = BTreeMap::from([
            ("providerKind".to_string(), "Ollama".to_string()),
            ("profileId".to_string(), "llama3.1:8b".to_string()),
            ("localityKind".to_string(), "Local".to_string()),
            ("customNote".to_string(), "keep me".to_string()),
        ]);

        let preserved = preserve_user_provider_metadata(&metadata);

        assert_eq!(preserved.get("customNote"), Some(&"keep me".to_string()));
        assert!(!preserved.contains_key("providerKind"));
        assert!(!preserved.contains_key("profileId"));
        assert!(!preserved.contains_key("localityKind"));
    }

